export declare const AzureKubernetesServiceRules = "\n# Azure Kubernetes Service (AKS) - WAF Rules for IaC\n\n- Deploy cluster across multiple availability zones\n- Use system-assigned managed identity for cluster authentication\n- Configure cluster autoscaler for node scaling\n- Use private clusters to isolate API server access\n- Enable Azure AD integration for authentication\n- Configure RBAC with Kubernetes role definitions\n- Enable Azure Policy for Kubernetes for policy enforcement\n- Configure network policy (Azure or Calico)\n- Link to Azure Container Registry\n- Enable diagnostic logging to Log Analytics workspace\n- Configure appropriate VM SKUs for node pools\n- Use SSD-based storage classes for production workloads\n";
